package com.example.documentviewer;

import android.content.ContentResolver;
import android.content.Intent;
import android.graphics.Bitmap;
import android.graphics.BitmapFactory;
import android.graphics.pdf.PdfRenderer;
import android.net.Uri;
import android.os.Bundle;
import android.os.ParcelFileDescriptor;
import android.view.ViewGroup;
import android.widget.FrameLayout;
import android.widget.ImageView;
import android.widget.Toast;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

import java.io.InputStream;

public class DocumentViewActivity extends AppCompatActivity {

    private FrameLayout root;
    private ImageView imageView;

    private ParcelFileDescriptor pdfPfd;
    private PdfRenderer pdfRenderer;
    private PdfRenderer.Page currentPage;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        root = new FrameLayout(this);
        root.setLayoutParams(new FrameLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.MATCH_PARENT
        ));

        imageView = new ImageView(this);
        imageView.setLayoutParams(new FrameLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.MATCH_PARENT
        ));
        imageView.setAdjustViewBounds(true);
        imageView.setScaleType(ImageView.ScaleType.FIT_CENTER);

        root.addView(imageView);
        setContentView(root);

        handleIntent(getIntent());
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        handleIntent(intent);
    }

    private void handleIntent(@Nullable Intent intent) {
        if (intent == null) return;

        String action = intent.getAction();
        if (!Intent.ACTION_VIEW.equals(action)) {
            Toast.makeText(this, "Unsupported action", Toast.LENGTH_SHORT).show();
            return;
        }

        Uri uri = intent.getData();
        if (uri == null) {
            Toast.makeText(this, "No file provided", Toast.LENGTH_SHORT).show();
            return;
        }

        String type = intent.getType();
        if (type == null) {
            type = getContentResolver().getType(uri);
        }

        closePdf();

        if (type != null && type.equalsIgnoreCase("application/pdf")) {
            renderPdfFirstPage(uri);
            return;
        }

        if (type != null && type.startsWith("image/")) {
            renderImage(uri);
            return;
        }

        String path = uri.toString().toLowerCase();
        if (path.endsWith(".pdf")) {
            renderPdfFirstPage(uri);
        } else {
            renderImage(uri);
        }
    }

    private void renderImage(Uri uri) {
        try (InputStream is = getContentResolver().openInputStream(uri)) {
            if (is == null) {
                Toast.makeText(this, "Unable to open file", Toast.LENGTH_SHORT).show();
                return;
            }
            Bitmap bitmap = BitmapFactory.decodeStream(is);
            if (bitmap == null) {
                Toast.makeText(this, "Unsupported image", Toast.LENGTH_SHORT).show();
                return;
            }
            imageView.setImageBitmap(bitmap);
        } catch (Exception e) {
            Toast.makeText(this, "Failed to open image", Toast.LENGTH_SHORT).show();
        }
    }

    private void renderPdfFirstPage(Uri uri) {
        try {
            ContentResolver resolver = getContentResolver();
            pdfPfd = resolver.openFileDescriptor(uri, "r");
            if (pdfPfd == null) {
                Toast.makeText(this, "Unable to open PDF", Toast.LENGTH_SHORT).show();
                return;
            }

            pdfRenderer = new PdfRenderer(pdfPfd);
            if (pdfRenderer.getPageCount() <= 0) {
                Toast.makeText(this, "Empty PDF", Toast.LENGTH_SHORT).show();
                closePdf();
                return;
            }

            currentPage = pdfRenderer.openPage(0);

            int width = currentPage.getWidth();
            int height = currentPage.getHeight();
            if (width <= 0 || height <= 0) {
                Toast.makeText(this, "Invalid PDF page", Toast.LENGTH_SHORT).show();
                closePdf();
                return;
            }

            Bitmap bitmap = Bitmap.createBitmap(width, height, Bitmap.Config.ARGB_8888);
            currentPage.render(bitmap, null, null, PdfRenderer.Page.RENDER_MODE_FOR_DISPLAY);
            imageView.setImageBitmap(bitmap);
        } catch (SecurityException se) {
            Toast.makeText(this, "Permission denied", Toast.LENGTH_SHORT).show();
            closePdf();
        } catch (Exception e) {
            Toast.makeText(this, "Failed to open PDF", Toast.LENGTH_SHORT).show();
            closePdf();
        }
    }

    private void closePdf() {
        try {
            if (currentPage != null) {
                currentPage.close();
                currentPage = null;
            }
        } catch (Exception ignored) { }

        try {
            if (pdfRenderer != null) {
                pdfRenderer.close();
                pdfRenderer = null;
            }
        } catch (Exception ignored) { }

        try {
            if (pdfPfd != null) {
                pdfPfd.close();
                pdfPfd = null;
            }
        } catch (Exception ignored) { }
    }

    @Override
    protected void onDestroy() {
        super.onDestroy();
        closePdf();
    }
}


